var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>《프로젝트 테라사이드 제 4차 실험 보고서》</color>","JPN":"<color=#ffd34c>《プロジェクト・テラサイド、第4次実験報告書》</color>","ENG":"<color=#ffd34c>《Project Terraside - 4th experiment report》</color>","TWN":"<color=#ffd34c>《特拉賽德專案第4次實驗報告書》</color>"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>이터니움을 베이스로 한 나노 변이 인자 테스트는 성공적.</color>","JPN":"<color=#ffd34c>エタニウムをベースとしたナノ変異ファクターテストは成功。</color>","ENG":"<color=#ffd34c>The Eternium-based nano mutation factor test was a success.</color>","TWN":"<color=#ffd34c>以永恆之金為基礎的納米變異因子試驗成功。</color>"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>최초 변이 시에는 외부에서 인자를 공급해야 하지만 이후 육체의 대사기능을 전용하여 변이 인자의 자가복제, 재생산이 가능.</color>","JPN":"<color=#ffd34c>初変異の際に、外部からファクターを供給しなければならないが、\\n以降は肉体の代謝機能を転用し、変異ファクターの自己複製や再生産が可能。</color>","ENG":"<color=#ffd34c>Although the factors must be provided from outside for the initial mutation phase, the mutation factors can duplicate and reproduce themselves using the host's metabolic system afterwards.</color>","TWN":"<color=#ffd34c>雖然在最初變異時，需要從外部供給因子，但是之後可以指定肉體的代謝機能，使變異因子能夠自我複製、再生產。</color>"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>재생산된 변이 인자의 고밀도집속 및 재설계를 통해 【최종 변이 인자】 제작 가능성 확인.</color>","JPN":"<color=#ffd34c>再生産された変異ファクターの高密度集束および再設計により\\n【最終変異ファクター】の製作可能性を確認。</color>","ENG":"<color=#ffd34c>This confirms the viability of creating the 【Ultimate Mutation Factors】 through high-density integration and redesign of reproduced mutation factors.</color>","TWN":"<color=#ffd34c>通過再生產出來的變異因子高密度集聚和再設計，確認可以製作【最終變異因子】。</color>"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>단, 충분한 양의 변이 인자를 시간 내에 생산하기 위한 특단의 대책 필요.</color>","JPN":"<color=#ffd34c>ただし、十分な量の変異ファクターを期限内に生産するための特段の対策が必要。</color>","ENG":"<color=#ffd34c>However, a special measure is required to ensure better mutation factor production efficiency.</color>","TWN":"<color=#ffd34c>只是，要在時間內生產足量的變異因子需要使用特別的對策。</color>"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>현 추세대로 진행될 경우 잔여 생존 인류 절멸까지 약......</color>","JPN":"<color=#ffd34c>現在の傾向が続く場合、残りの生存人類の絶滅まで約……</color>","ENG":"<color=#ffd34c>Considering the speed of progression, the estimated time until the complete extinction of the remaining population is...</color>","TWN":"<color=#ffd34c>按照現在的趨勢進行下去，剩下的人類離滅絕大約……</color>"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"서, 선배?!","JPN":"せ、先輩！？","ENG":"Sh-Shiyoon?","TWN":"前、前輩？！"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>데이터를 삭제하시겠습니까?</color>","JPN":"<color=#ffd34c>データを削除しますか？</color>","ENG":"<color=#ffd34c>Do you want to delete the data?</color>","TWN":"<color=#ffd34c>要刪除資料嗎？</color>"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>Yes</color>","JPN":"<color=#ffd34c>Yes</color>","ENG":"<color=#ffd34c>Yes</color>","TWN":"<color=#ffd34c>Yes</color>"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>데이터가 모두 삭제되었습니다.</color>","JPN":"<color=#ffd34c>データがすべて削除されました。</color>","ENG":"<color=#ffd34c>All data has been deleted.</color>","TWN":"<color=#ffd34c>資料已全部刪除。</color>"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"이런 곳에 있었어?","JPN":"こんなところにいたの？","ENG":"I didn't expect to meet you here.","TWN":"你怎麼會在這種地方？"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"아, 미나 양.","JPN":"あ、ミナさん。","ENG":"Oh, Mina.","TWN":"啊，米娜小姐。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"다행이네요. 이러다 꼼짝없이 혼자 미아가 되는 게 아닌가 했었거든요.","JPN":"よかったです、このまま一人ぼっちで迷子になるんじゃないかと思いました。","ENG":"Thank goodness. I was lost out there alone and thought I'd be lost forever.","TWN":"真是太好了呢。我還以為再這樣下去，我就要迷路了呢。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"일행들을 찾다가 뉴 오하이오가 대파되는 모습을 보고 여기로 왔는데......","JPN":"捜索中にニューオハイオが大破するのを見かけたので、ここに来たのですが……","ENG":"I saw the New Ohio sink while looking all over for allies and headed here.","TWN":"我在尋找同伴的時候，發現新俄亥俄被破壞了，所以就過來看看……"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"여기서 미나 양을 만나게 되다니, 역시 이게 정답이었나 보네요. 하하.","JPN":"ここでミナさんと落ち合えたので、やっぱりこれが正解だったみたいですね、ハハ。","ENG":"You being here proves I made the right move, Hah hah.","TWN":"結果竟然能在這裡遇到米娜小姐，看來我來這裡是正確的決定呢。哈哈。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그, 그보다 온몸이 피투성이잖아? 괜찮은 거야?","JPN":"そ、それより、全身が血だらけじゃない？　大丈夫なの？","ENG":"B-but you have blood all over you! What happened?","TWN":"話，話說你全身都是血耶？你沒事嗎？"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L23_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"아아...... 이거 말인가요?","JPN":"ああ……これのことですか？","ENG":"Ah, this?","TWN":"啊啊……妳說這個嗎？"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L24_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"이건 그러니까...... 오는 길에 괴물과 마주쳐서 말이죠.","JPN":"これはですね……道中でバケモノに出くわしてしまって。","ENG":"This is... Well, I ran into a monster on the way here.","TWN":"這是因為……我在來的路上碰到了怪物。"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}}]`);export{e as default};